import { translateString } from '../../../utils/svg-transforms';
import { getMarkValue } from '../../parser/parser-helpers';

function groupMark(config, cache) {
    return {
        config: {
            transform: function(d, i) {
                let node = this,
                    args = [d, i],
                    _x,
                    _y;

                if (config.transform) {
                    ({ x: _x, y: _y } = getMarkValue(node, args, config, 'transform', cache));
                } else {
                    _x = getMarkValue(node, args, config, 'x', cache);
                    _y = getMarkValue(node, args, config, 'y', cache);
                }

                return translateString([_x, _y]);
            }
        },
        depends: {
            transform: ['x', 'y']
        }
    };
}

export { groupMark };
